import React from 'react';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Button, Input } from '../../ui';
import {
  jobsService,
  type PlatformEventingRuntimeConfig,
  type UpdatePlatformEventingRuntimeConfigRequest,
} from '../../services/jobs';
import styles from './PlatformEventingConfigPanel.module.css';

export type PlatformEventingConfigPanelProps = {
  compact?: boolean;
};

const num = (v: string, fallback: number) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const draftFromConfig = (c: PlatformEventingRuntimeConfig): UpdatePlatformEventingRuntimeConfigRequest => ({
  lowWorkerInstanceCount: c.lowWorkerInstanceCount,
  lowClusterInstanceCount: c.lowClusterInstanceCount,
  lowWorkerSlot: c.lowWorkerSlot,
  lowUseLeaderElection: c.lowUseLeaderElection,
  lowBatchSize: c.lowBatchSize,
  lowPollIntervalMinMs: c.lowPollIntervalMinMs,
  lowPollIntervalMaxMs: c.lowPollIntervalMaxMs,
  lowIntervalMinutes: c.lowIntervalMinutes,
  highBatchSize: c.highBatchSize,
  highPollIntervalMinMs: c.highPollIntervalMinMs,
  highPollIntervalMaxMs: c.highPollIntervalMaxMs,
  leaseDurationSeconds: c.leaseDurationSeconds,
  defaultMaxAttempts: c.defaultMaxAttempts,
  usePostgresListenNotify: c.usePostgresListenNotify,
  failOrphanedProcessingOnWorkerStart: c.failOrphanedProcessingOnWorkerStart,
  logWorkerLifecycle: c.logWorkerLifecycle,
  logEventProcessing: c.logEventProcessing,
  logPollingDetail: c.logPollingDetail,
});

const PlatformEventingConfigPanel: React.FC<PlatformEventingConfigPanelProps> = ({ compact }) => {
  const toast = useAppToast();
  const [config, setConfig] = React.useState<PlatformEventingRuntimeConfig | null>(null);
  const [draft, setDraft] = React.useState<UpdatePlatformEventingRuntimeConfigRequest>({});
  const [showAdvanced, setShowAdvanced] = React.useState(false);
  const [loading, setLoading] = React.useState(true);
  const [saving, setSaving] = React.useState(false);

  const clusterCount = draft.lowClusterInstanceCount ?? config?.lowClusterInstanceCount ?? 1;
  const showClusterFields = clusterCount > 1;

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getEventingRuntimeConfig()
      .then((c) => {
        setConfig(c);
        setDraft(draftFromConfig(c));
      })
      .catch((e: Error) => {
        toast.error(e.message);
        setConfig(null);
      })
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => {
    load();
  }, [load]);

  const save = async () => {
    setSaving(true);
    try {
      const saved = await jobsService.updateEventingRuntimeConfig(draft);
      setConfig(saved);
      setDraft(draftFromConfig(saved));
      toast.success('Đã lưu cấu hình worker');
      if (saved.applyNote) toast.info(saved.applyNote);
      if (saved.requiresRestartOnSave) {
        toast.warning('Cần restart container worker để áp dụng topology / LISTEN.');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi lưu');
    } finally {
      setSaving(false);
    }
  };

  if (loading && !config) {
    return (
      <div className={styles.panel} data-testid="platform-eventing-config-panel">
        <p className={styles.muted}>Đang tải cấu hình worker…</p>
      </div>
    );
  }

  if (!config) {
    return (
      <div className={styles.panel} data-testid="platform-eventing-config-panel">
        <p className={styles.warn}>Không tải được cấu hình worker.</p>
        <Button type="button" variant="secondary" onClick={load}>
          Thử lại
        </Button>
      </div>
    );
  }

  return (
    <div
      className={`${styles.panel} ${compact ? styles.panelCompact : ''}`}
      data-testid="platform-eventing-config-panel"
    >
      <div className={styles.header}>
        <div>
          <strong>Cấu hình worker queue (Low / High)</strong>
          {!compact ? (
            <p className={styles.hint}>
              Lưu vào <code>SystemSettings.PlatformEventing.Runtime</code> — restart worker đọc lại
              seed/Admin. Chỉ <code>RunWorkers</code> / <code>Enabled</code> giữ trên env deploy.
            </p>
          ) : null}
        </div>
        {!compact ? (
          <Button type="button" variant="secondary" onClick={load} disabled={loading || saving}>
            Làm mới
          </Button>
        ) : null}
      </div>

      {config.hasDbOverride ? (
        <p className={styles.noteOk}>Đã có cấu hình DB — {config.applyNote}</p>
      ) : (
        <p className={styles.note}>{config.applyNote}</p>
      )}

      <h4 className={styles.sectionTitle}>Low tier (ghi sổ import, sync…)</h4>
      <div className={styles.grid}>
        <Input
          label="Số worker / host (LowWorkerInstanceCount)"
          type="number"
          min={1}
          max={16}
          value={String(draft.lowWorkerInstanceCount ?? config.lowWorkerInstanceCount)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, lowWorkerInstanceCount: num(e.target.value, 1) }))
          }
          data-testid="eventing-low-worker-instances"
        />
        <Input
          label="Partition cluster (LowClusterInstanceCount)"
          type="number"
          min={1}
          max={32}
          value={String(draft.lowClusterInstanceCount ?? config.lowClusterInstanceCount)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, lowClusterInstanceCount: num(e.target.value, 1) }))
          }
        />
        {showClusterFields ? (
          <Input
            label="Slot host (LowWorkerSlot, 0-based)"
            type="number"
            min={0}
            max={31}
            value={String(draft.lowWorkerSlot ?? config.lowWorkerSlot)}
            onChange={(e) => setDraft((d) => ({ ...d, lowWorkerSlot: num(e.target.value, 0) }))}
          />
        ) : (
          <p className={styles.muted}>
            Cluster = 1 — slot tự động. Tăng cluster khi scale nhiều replica worker.
          </p>
        )}
        <Input
          label="Batch mỗi vòng (LowBatchSize)"
          type="number"
          min={1}
          max={500}
          value={String(draft.lowBatchSize ?? config.lowBatchSize)}
          onChange={(e) => setDraft((d) => ({ ...d, lowBatchSize: num(e.target.value, 50) }))}
        />
        <Input
          label="Poll idle min (ms)"
          type="number"
          min={1000}
          value={String(draft.lowPollIntervalMinMs ?? config.lowPollIntervalMinMs)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, lowPollIntervalMinMs: num(e.target.value, 5000) }))
          }
        />
        <Input
          label="Poll idle max (ms, 0 = dùng phút)"
          type="number"
          min={0}
          value={String(draft.lowPollIntervalMaxMs ?? config.lowPollIntervalMaxMs)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, lowPollIntervalMaxMs: num(e.target.value, 0) }))
          }
        />
        <Input
          label="Max idle (phút, legacy)"
          type="number"
          min={1}
          max={120}
          value={String(draft.lowIntervalMinutes ?? config.lowIntervalMinutes)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, lowIntervalMinutes: num(e.target.value, 5) }))
          }
        />
      </div>

      <h4 className={styles.sectionTitle}>High tier (ghi sổ tay, user post)</h4>
      <div className={styles.grid}>
        <Input
          label="Batch High (HighBatchSize)"
          type="number"
          min={1}
          max={100}
          value={String(draft.highBatchSize ?? config.highBatchSize)}
          onChange={(e) => setDraft((d) => ({ ...d, highBatchSize: num(e.target.value, 20) }))}
        />
        <Input
          label="Poll High min (ms)"
          type="number"
          min={50}
          value={String(draft.highPollIntervalMinMs ?? config.highPollIntervalMinMs)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, highPollIntervalMinMs: num(e.target.value, 200) }))
          }
        />
        <Input
          label="Poll High max (ms)"
          type="number"
          min={100}
          value={String(draft.highPollIntervalMaxMs ?? config.highPollIntervalMaxMs)}
          onChange={(e) =>
            setDraft((d) => ({ ...d, highPollIntervalMaxMs: num(e.target.value, 5000) }))
          }
        />
      </div>

      <div className={styles.actions}>
        <Button
          type="button"
          variant="secondary"
          onClick={() => setShowAdvanced((v) => !v)}
          data-testid="eventing-config-toggle-advanced"
        >
          {showAdvanced ? 'Ẩn nâng cao' : 'Nâng cao (lease, retry, LISTEN…)'}
        </Button>
      </div>

      {showAdvanced ? (
        <>
          <div className={styles.grid}>
            <Input
              label="Lease (giây)"
              type="number"
              min={30}
              max={7200}
              value={String(draft.leaseDurationSeconds ?? config.leaseDurationSeconds)}
              onChange={(e) =>
                setDraft((d) => ({ ...d, leaseDurationSeconds: num(e.target.value, 600) }))
              }
            />
            <Input
              label="Retry tối đa (DefaultMaxAttempts)"
              type="number"
              min={1}
              max={20}
              value={String(draft.defaultMaxAttempts ?? config.defaultMaxAttempts)}
              onChange={(e) =>
                setDraft((d) => ({ ...d, defaultMaxAttempts: num(e.target.value, 5) }))
              }
            />
          </div>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={draft.lowUseLeaderElection ?? config.lowUseLeaderElection}
              onChange={(e) => setDraft((d) => ({ ...d, lowUseLeaderElection: e.target.checked }))}
              data-testid="eventing-low-leader-election"
            />
            <span>
              Leader election — 1 coordinator promote/reconcile / cluster (bắt buộc multi-replica)
            </span>
          </label>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={draft.usePostgresListenNotify ?? config.usePostgresListenNotify}
              onChange={(e) => setDraft((d) => ({ ...d, usePostgresListenNotify: e.target.checked }))}
            />
            <span>LISTEN/NOTIFY đánh thức worker (cần restart)</span>
          </label>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={
                draft.failOrphanedProcessingOnWorkerStart ??
                config.failOrphanedProcessingOnWorkerStart
              }
              onChange={(e) =>
                setDraft((d) => ({ ...d, failOrphanedProcessingOnWorkerStart: e.target.checked }))
              }
            />
            <span>Fail orphan Processing khi worker start (cần restart)</span>
          </label>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={draft.logWorkerLifecycle ?? config.logWorkerLifecycle}
              onChange={(e) => setDraft((d) => ({ ...d, logWorkerLifecycle: e.target.checked }))}
            />
            <span>Log lifecycle worker</span>
          </label>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={draft.logEventProcessing ?? config.logEventProcessing}
              onChange={(e) => setDraft((d) => ({ ...d, logEventProcessing: e.target.checked }))}
            />
            <span>Log từng event xử lý</span>
          </label>
          <label className={styles.checkRow}>
            <input
              type="checkbox"
              checked={draft.logPollingDetail ?? config.logPollingDetail}
              onChange={(e) => setDraft((d) => ({ ...d, logPollingDetail: e.target.checked }))}
            />
            <span>Log chi tiết mỗi vòng poll</span>
          </label>
        </>
      ) : null}

      <div className={styles.actions}>
        <Button type="button" onClick={() => void save()} disabled={saving || loading}>
          {saving ? 'Đang lưu…' : 'Lưu cấu hình worker'}
        </Button>
      </div>
    </div>
  );
};

export default PlatformEventingConfigPanel;
