import React from 'react';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Button } from '../../../ui';
import { jobsService } from '../../../services/jobs';

export type JobEventQueueActionsProps = {
  eventType?: string;
  queuedTotal?: number;
  onDone: () => void;
};

export const JobEventQueueActions: React.FC<JobEventQueueActionsProps> = ({
  eventType,
  queuedTotal = 0,
  onDone,
}) => {
  const toast = useAppToast();
  const [previewCount, setPreviewCount] = React.useState<number | null>(null);
  const [loadingPreview, setLoadingPreview] = React.useState(false);
  const [cancelling, setCancelling] = React.useState(false);
  const [reprioritizing, setReprioritizing] = React.useState(false);

  React.useEffect(() => {
    if (queuedTotal <= 0) {
      setPreviewCount(null);
      return;
    }
    setLoadingPreview(true);
    jobsService
      .getCancelQueuedPreview(eventType || undefined)
      .then((p) => setPreviewCount(p.eligibleCount))
      .catch(() => setPreviewCount(null))
      .finally(() => setLoadingPreview(false));
  }, [eventType, queuedTotal]);

  const handleCancelQueued = () => {
    const label = eventType || 'mọi loại';
    const count = previewCount ?? queuedTotal;
    if (!window.confirm(`Hủy tối đa 5.000 event Queued (${label})? Hiện có ~${count.toLocaleString('vi-VN')} event.`)) {
      return;
    }
    setCancelling(true);
    jobsService
      .cancelQueuedEvents({ eventType: eventType || undefined, maxCount: 5_000 })
      .then((r) => {
        toast.success(`Đã hủy ${r.cancelledCount.toLocaleString('vi-VN')} event Queued`);
        onDone();
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setCancelling(false));
  };

  const handleReprioritize = () => {
    const label = eventType || 'mọi loại';
    if (!window.confirm(`Đẩy ưu tiên (priority -10) tối đa 5.000 event Queued — ${label}?`)) {
      return;
    }
    setReprioritizing(true);
    jobsService
      .reprioritizeQueuedEvents({ eventType: eventType || undefined, priority: -10, maxCount: 5_000 })
      .then((r) => {
        toast.success(`Đã cập nhật ưu tiên ${r.updatedCount.toLocaleString('vi-VN')} event`);
        onDone();
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setReprioritizing(false));
  };

  if (queuedTotal <= 0) return null;

  return (
    <div
      style={{
        marginBottom: 16,
        padding: '10px 14px',
        background: '#fff7ed',
        border: '1px solid #fed7aa',
        borderRadius: 8,
        fontSize: 13,
        display: 'flex',
        flexWrap: 'wrap',
        gap: 10,
        alignItems: 'center',
      }}
      data-testid="job-event-queue-actions"
    >
      <span style={{ color: '#9a3412' }}>
        Vận hành hàng đợi
        {eventType ? (
          <>
            {' '}
            — <code>{eventType}</code>
          </>
        ) : null}
        {loadingPreview ? '…' : previewCount != null ? ` (${previewCount.toLocaleString('vi-VN')} Queued)` : null}
      </span>
      <Button
        type="button"
        variant="secondary"
        disabled={reprioritizing || cancelling}
        onClick={handleReprioritize}
        data-testid="reprioritize-queued-btn"
      >
        {reprioritizing ? 'Đang đẩy…' : 'Đẩy ưu tiên'}
      </Button>
      <Button
        type="button"
        variant="secondary"
        disabled={cancelling || reprioritizing}
        onClick={handleCancelQueued}
        data-testid="cancel-queued-btn"
      >
        {cancelling ? 'Đang hủy…' : 'Hủy Queued'}
      </Button>
    </div>
  );
};
