import React, { useCallback, useEffect, useState } from 'react';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Pagination } from '../../../ui';
import { jobsService, type DataSyncRunDetail, type ExternalSyncVoucherSample } from '../../../services/jobs';
import { JobDetailCollapsibleSection } from './JobDetailMetaGrid';
import { connectorLabel } from '../externalSyncRunDisplay';
import { displayExternalVoucherImportOutcome } from '../jobStatusDisplay';
import { isExternalSyncVoucherLinkable } from '../externalSyncVoucherViewPath';
import { openConvertedExternalSyncVoucher } from '../externalSyncVoucherNavigate';
import styles from '../JobInternalPage.module.css';

const PAGE_SIZE = 20;

export type ExternalSyncVoucherSamplesSectionProps = {
  runDetail: DataSyncRunDetail;
};

export const ExternalSyncVoucherSamplesSection: React.FC<ExternalSyncVoucherSamplesSectionProps> = ({
  runDetail,
}) => {
  const toast = useAppToast();
  const totalHint =
    runDetail.voucherSampleCount ??
    runDetail.conversionSummary?.documentsConverted ??
    runDetail.voucherSamples?.length ??
    0;

  const [page, setPage] = useState(1);
  const [items, setItems] = useState<ExternalSyncVoucherSample[]>([]);
  const [total, setTotal] = useState(0);
  const [filterLoading, setFilterLoading] = useState(false);
  const [pageLoading, setPageLoading] = useState(false);
  const [openingVoucherKey, setOpeningVoucherKey] = useState<string | null>(null);

  const loadPage = useCallback(
    async (targetPage: number, mode: 'filter' | 'page') => {
      if (mode === 'filter') setFilterLoading(true);
      else setPageLoading(true);
      try {
        const result = await jobsService.getExternalVoucherSamples(runDetail.id, targetPage, PAGE_SIZE);
        setItems(result.items);
        setTotal(result.total);
        setPage(targetPage);
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Không tải được danh sách chứng từ.';
        toast.error(message);
      } finally {
        if (mode === 'filter') setFilterLoading(false);
        else setPageLoading(false);
      }
    },
    [runDetail.id, toast],
  );

  useEffect(() => {
    if (totalHint <= 0) {
      setItems([]);
      setTotal(0);
      return;
    }
    void loadPage(1, 'filter');
  }, [runDetail.id, totalHint, loadPage]);

  const openConvertedVoucher = useCallback(
    async (sample: ExternalSyncVoucherSample) => {
      const code = sample.voucherCode?.trim();
      if (!code || !isExternalSyncVoucherLinkable(sample.setName, code)) return;

      const rowKey = `${sample.setName}-${sample.externalId}-${code}`;
      setOpeningVoucherKey(rowKey);
      try {
        await openConvertedExternalSyncVoucher(runDetail, sample);
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Không mở được chứng từ ERP.';
        toast.error(message);
      } finally {
        setOpeningVoucherKey(null);
      }
    },
    [runDetail, toast],
  );

  if (totalHint <= 0 && total <= 0 && !filterLoading) return null;

  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
  const sttBase = (page - 1) * PAGE_SIZE;
  const showTableLoading = filterLoading;

  return (
    <JobDetailCollapsibleSection title={`Mã chứng từ đã convert (${total.toLocaleString('vi-VN')})`}>
      <div className={pageLoading ? styles.gridBusy : undefined} aria-busy={pageLoading || undefined}>
        <div className={styles.detailTableWrap}>
          {showTableLoading ? (
            <p className={styles.gridLoading}>Đang tải…</p>
          ) : items.length === 0 ? (
            <p className={styles.gridEmpty}>Chưa có mẫu chứng từ đã lưu cho run này.</p>
          ) : (
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th align="right">STT</th>
                  <th>Loại</th>
                  <th>Mã POS</th>
                  <th>Mã CT ERP</th>
                  <th>Kết quả</th>
                </tr>
              </thead>
              <tbody>
                {items.map((v, idx) => {
                  const code = v.voucherCode?.trim() ?? '';
                  const linkable = code.length > 0 && isExternalSyncVoucherLinkable(v.setName, code);
                  const rowKey = `${v.setName}-${v.externalId}-${code || idx}`;
                  const opening = openingVoucherKey === rowKey;
                  return (
                    <tr key={rowKey}>
                      <td align="right">{sttBase + idx + 1}</td>
                      <td>{connectorLabel(v.setName)}</td>
                      <td className={styles.gridMono}>{v.externalId}</td>
                      <td className={styles.gridMono}>
                        {linkable ? (
                          <button
                            type="button"
                            className={styles.linkButton}
                            title="Mở chứng từ ERP (tab mới)"
                            disabled={opening}
                            onClick={() => void openConvertedVoucher(v)}
                          >
                            {opening ? 'Đang mở…' : code}
                          </button>
                        ) : (
                          v.voucherCode ?? '—'
                        )}
                      </td>
                      <td>{displayExternalVoucherImportOutcome(v.isNewInsert)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>
      </div>
      {!showTableLoading && total > 0 ? (
        <div style={{ marginTop: 12 }}>
          <Pagination
            currentPage={page}
            totalPages={totalPages}
            totalCount={total}
            pageSize={PAGE_SIZE}
            itemLabel="chứng từ"
            onPageChange={(next) => void loadPage(next, 'page')}
          />
        </div>
      ) : null}
    </JobDetailCollapsibleSection>
  );
};
