/**
 * Unified platform job display status — mirrors BE PlatformJobDisplayStatuses.
 * Raw persistence: Pending → Queued, Processing → Running, Completed/Success → Done.
 */

export const PlatformJobStatus = {
  Queued: 'Queued',
  Running: 'Running',
  Done: 'Done',
  Failed: 'Failed',
  RetryPending: 'RetryPending',
  Partial: 'Partial',
  Cancelled: 'Cancelled',
  Skipped: 'Skipped',
  Stopped: 'Stopped',
  Sleep: 'Sleep',
} as const;

export type PlatformJobStatusValue = (typeof PlatformJobStatus)[keyof typeof PlatformJobStatus];

const RAW_TO_DISPLAY: Record<string, PlatformJobStatusValue> = {
  Pending: PlatformJobStatus.Queued,
  Processing: PlatformJobStatus.Running,
  Completed: PlatformJobStatus.Done,
  Success: PlatformJobStatus.Done,
  DeadLetter: PlatformJobStatus.Failed,
  Cancelled: PlatformJobStatus.Cancelled,
  Skipped: PlatformJobStatus.Skipped,
  Partial: PlatformJobStatus.Partial,
  RetryPending: PlatformJobStatus.RetryPending,
  Running: PlatformJobStatus.Running,
  Queued: PlatformJobStatus.Queued,
  Done: PlatformJobStatus.Done,
  Failed: PlatformJobStatus.Failed,
};

export const resolveEventJobStatus = (item: {
  jobStatus?: string | null;
  processingStatus: string;
  nextRetryAt?: string | null;
  attemptCount?: number;
  maxAttempts?: number;
}): PlatformJobStatusValue => {
  if (item.jobStatus) {
    const direct = RAW_TO_DISPLAY[item.jobStatus];
    if (direct) return direct;
    if (Object.values(PlatformJobStatus).includes(item.jobStatus as PlatformJobStatusValue)) {
      return item.jobStatus as PlatformJobStatusValue;
    }
  }

  if (item.processingStatus === 'Failed') {
    if (
      item.nextRetryAt &&
      (item.attemptCount ?? 0) < (item.maxAttempts ?? 5)
    ) {
      return PlatformJobStatus.RetryPending;
    }
    return PlatformJobStatus.Failed;
  }

  return RAW_TO_DISPLAY[item.processingStatus] ?? (item.processingStatus as PlatformJobStatusValue);
};

export const resolveRunJobStatus = (item: {
  runJobStatus?: string | null;
  runStatus?: string | null;
}): PlatformJobStatusValue | null => {
  const raw = item.runJobStatus ?? item.runStatus;
  if (!raw) return null;
  return RAW_TO_DISPLAY[raw] ?? (raw as PlatformJobStatusValue);
};

export const jobStatusLabelVi = (status: string): string => {
  switch (status) {
    case PlatformJobStatus.Queued:
      return 'Hàng đợi';
    case PlatformJobStatus.Running:
      return 'Đang chạy';
    case PlatformJobStatus.Done:
      return 'Hoàn tất';
    case PlatformJobStatus.Failed:
      return 'Lỗi';
    case PlatformJobStatus.RetryPending:
      return 'Chờ retry';
    case PlatformJobStatus.Partial:
      return 'Một phần';
    case PlatformJobStatus.Skipped:
      return 'Bỏ qua';
    case PlatformJobStatus.Cancelled:
      return 'Đã hủy';
    case PlatformJobStatus.Stopped:
      return 'Dừng';
    case PlatformJobStatus.Sleep:
      return 'Chờ lịch';
    default:
      return status;
  }
};

export const jobStatusColor = (status: string): string => {
  switch (status) {
    case PlatformJobStatus.Done:
    case 'Done':
      return '#15803d';
    case 'Skipped':
      return '#0369a1';
    case PlatformJobStatus.Failed:
      return '#b91c1c';
    case PlatformJobStatus.Running:
      return '#2563eb';
    case PlatformJobStatus.Queued:
      return '#7c3aed';
    case PlatformJobStatus.RetryPending:
    case PlatformJobStatus.Partial:
      return '#ca8a04';
    case PlatformJobStatus.Skipped:
    case PlatformJobStatus.Cancelled:
    case PlatformJobStatus.Sleep:
    case PlatformJobStatus.Stopped:
      return '#64748b';
    default:
      return '#64748b';
  }
};

export const isActiveJobStatus = (status: string): boolean =>
  status === PlatformJobStatus.Queued
  || status === PlatformJobStatus.Running
  || status === PlatformJobStatus.RetryPending;

export const JOB_STATUS_FILTER_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: PlatformJobStatus.Queued, label: 'Hàng đợi (Queued)' },
  { value: PlatformJobStatus.Running, label: 'Đang chạy (Running)' },
  { value: PlatformJobStatus.RetryPending, label: 'Chờ retry' },
  { value: PlatformJobStatus.Done, label: 'Hoàn tất (Done)' },
  { value: PlatformJobStatus.Failed, label: 'Lỗi (Failed)' },
  { value: PlatformJobStatus.Cancelled, label: 'Đã hủy' },
] as const;
