import type {
  ExternalConnectorPreviewResult,
  ExternalConnectorTestConnectResult,
  ExternalConnectorTestSearchResult,
} from '../../services/jobs';

const tryParseJson = (text?: string | null): unknown => {
  if (!text?.trim()) return null;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const mappingNotes = (
  preview: ExternalConnectorPreviewResult,
  status: 'error' | 'warn',
): string[] =>
  preview.fieldMappings
    .filter((m) => m.status === status)
    .map((m) => m.note ?? `${m.fmField} → ${m.erpField}: ${m.fmValue ?? '—'} → ${m.erpValue ?? '—'}`);

export const buildPreviewAiDebugBundle = (
  preview: ExternalConnectorPreviewResult,
  configKey?: string,
): string => {
  const fallbackRow = preview.fieldMappings.find((m) => m.erpField === 'detailFallback');
  const bundle = {
    _hint: 'Dán vào AI để phân tích lỗi REVA FM external sync / preview convert',
    configKey: configKey ?? null,
    success: preview.success,
    httpStatus: preview.httpStatus ?? null,
    message: preview.message,
    requestUrl: preview.requestUrl,
    elapsedMs: preview.elapsedMs,
    voucherTypeLabel: preview.voucherTypeLabel ?? null,
    totalItems: preview.totalItems,
    selectedDocumentKey: preview.selectedDocumentKey ?? null,
    sourceKind: preview.sourceKind ?? null,
    detailFallback: fallbackRow?.note ?? null,
    branchMap: preview.branchMap ?? null,
    errors: mappingNotes(preview, 'error'),
    warnings: mappingNotes(preview, 'warn'),
    fieldMappingIssues: preview.fieldMappings
      .filter((m) => m.status === 'error' || m.status === 'warn')
      .map((m) => ({
        fmField: m.fmField,
        erpField: m.erpField,
        status: m.status,
        note: m.note ?? null,
        fmValue: m.fmValue ?? null,
        erpValue: m.erpValue ?? null,
      })),
    fmSourceJson: tryParseJson(preview.fmSourceJson),
    erpPreviewJson: tryParseJson(preview.erpPreviewJson),
  };
  return JSON.stringify(bundle, null, 2);
};

export const buildPreviewResponseBundle = (preview: ExternalConnectorPreviewResult): string => {
  const payload = {
    fmSourceJson: tryParseJson(preview.fmSourceJson),
    erpPreviewJson: tryParseJson(preview.erpPreviewJson),
    searchItems: preview.searchItems.map((item) => ({
      documentKey: item.documentKey,
      label: item.label,
      rawJson: tryParseJson(item.rawJson),
    })),
  };
  return JSON.stringify(payload, null, 2);
};

export const buildTestConnectAiDebugBundle = (
  result: ExternalConnectorTestConnectResult,
  configKey?: string,
): string =>
  JSON.stringify(
    {
      _hint: 'Dán vào AI — test kết nối REVA FM search probe',
      configKey: configKey ?? null,
      kind: 'test-connect',
      success: result.success,
      httpStatus: result.httpStatus ?? null,
      message: result.message,
      requestUrl: result.requestUrl,
      totalItems: result.totalItems,
      elapsedMs: result.elapsedMs,
    },
    null,
    2,
  );

export const buildTestSearchAiDebugBundle = (
  result: ExternalConnectorTestSearchResult,
  configKey?: string,
): string =>
  JSON.stringify(
    {
      _hint: 'Dán vào AI — test search REVA FM',
      configKey: configKey ?? null,
      kind: 'test-search',
      success: result.success,
      httpStatus: result.httpStatus ?? null,
      message: result.message,
      requestUrl: result.requestUrl,
      totalItems: result.totalItems,
      itemCount: result.itemCount,
      elapsedMs: result.elapsedMs,
      responseJson: tryParseJson(result.responseJson),
    },
    null,
    2,
  );

export const previewDetailFallbackNote = (
  preview: ExternalConnectorPreviewResult,
): string | null =>
  preview.fieldMappings.find((m) => m.erpField === 'detailFallback')?.note ?? null;
