import React from 'react';
import { Link } from 'react-router-dom';
import { useAppToast, useActiveCompany } from '@linm-soft-org/linm-web-common-components';
import { Button, TableCard } from '../../../ui';
import type { ImportSetTrackingItem, ImportSetVersionHistoryItem } from '../../../services/jobs';
import { jobsService } from '../../../services/jobs';
import JobsListToolbar from '../JobsListToolbar';
import { filterBySearchQuery } from '../jobsListFilterUtils';
import { displayImportRunStatus, jobStatusColor } from '../jobStatusDisplay';
import styles from '../JobInternalPage.module.css';

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

export const displayImportSetStatus = (status: string): string => {
  if (status === 'NotImported') return 'Chưa import';
  return displayImportRunStatus(status);
};

const formatVersionLabel = (importDate?: string | null, importVersion?: string | null): string => {
  if (!importDate && !importVersion) return '—';
  if (importDate && importVersion) return `${importDate} · v${importVersion}`;
  return importVersion ? `v${importVersion}` : (importDate ?? '—');
};

const VersionHistoryTable: React.FC<{ item: ImportSetTrackingItem }> = ({ item }) => {
  if (item.versionHistory.length === 0) {
    return <p style={{ fontSize: 13, color: '#64748b', margin: '8px 0 0' }}>Chưa có lịch sử version đã ghi nhận.</p>;
  }

  return (
    <div className={styles.detailTableWrap} style={{ marginTop: 8 }}>
      <table className={styles.detailTable}>
        <thead>
          <tr>
            <th>Ngày seed</th>
            <th>Version</th>
            <th>Import lúc</th>
            <th>Trạng thái set</th>
            <th align="right">Tổng dòng</th>
            <th align="right">Upsert</th>
            <th>Run</th>
          </tr>
        </thead>
        <tbody>
          {item.versionHistory.map((h: ImportSetVersionHistoryItem) => (
            <tr key={`${h.importDate}-${h.importVersion}-${h.appliedAtUtc}`}>
              <td>{h.importDate || '—'}</td>
              <td>{h.importVersion ? `v${h.importVersion}` : '—'}</td>
              <td>{formatDate(h.appliedAtUtc)}</td>
              <td style={{ color: jobStatusColor(h.setStatus ?? h.runStatus ?? '') }}>
                {displayImportSetStatus(h.setStatus ?? h.runStatus ?? '—')}
              </td>
              <td align="right">{h.totalRecords.toLocaleString('vi-VN')}</td>
              <td align="right">{h.rowsUpserted.toLocaleString('vi-VN')}</td>
              <td>
                <Link to={`/admin/jobs/internal?tab=import&runId=${h.runId}`} className={styles.detailActionLink}>
                  {h.runId.slice(0, 8)}…
                </Link>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export type JobImportSetTrackingPanelProps = {
  onOpenRun?: (runId: string) => void;
};

export const JobImportSetTrackingPanel: React.FC<JobImportSetTrackingPanelProps> = ({ onOpenRun }) => {
  const toast = useAppToast();
  const { companyId: activeCompanyId } = useActiveCompany();
  const [items, setItems] = React.useState<ImportSetTrackingItem[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [loadError, setLoadError] = React.useState<string | null>(null);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [expandedSet, setExpandedSet] = React.useState<string | null>(null);

  const loadTracking = React.useCallback(() => {
    setLoading(true);
    setLoadError(null);
    jobsService
      .getImportSetTracking()
      .then((rows) => {
        setItems(rows);
        setLoadError(null);
      })
      .catch((e: Error) => {
        setItems([]);
        setLoadError(e.message);
        toast.error(e.message);
      })
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => {
    loadTracking();
  }, [loadTracking]);

  const filtered = React.useMemo(
    () =>
      filterBySearchQuery<ImportSetTrackingItem>(items, searchQuery, (row) =>
        [row.setName, row.description, row.latestVersion, row.appliedVersion, row.importStatus].join(' '),
      ),
    [items, searchQuery],
  );

  return (
    <TableCard
      listShell
      header={
        <div>
          <h4 className={styles.listHeaderTitle}>Theo dõi import set CSV</h4>
          <p className={styles.listHint}>
            Trạng thái import theo từng set · version mới nhất từ manifest trên disk · lịch sử fingerprint đã apply.
            {activeCompanyId ? (
              <>
                {' '}
                Đơn vị: <code>{activeCompanyId}</code> (<code>X-Company-Id</code>).
              </>
            ) : (
              <>
                {' '}
                Chưa chọn đơn vị — API dùng <code>MasterDataImport:DefaultCompanyId</code> nếu có.
              </>
            )}
          </p>
          <JobsListToolbar
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            searchPlaceholder="Tìm set, version…"
            searchTestId="job-import-set-tracking-search"
            onRefresh={loadTracking}
            totalCount={items.length}
            filteredCount={filtered.length}
            loading={loading}
            itemLabel="set"
          />
        </div>
      }
    >
      <div className={styles.detailTableWrap}>
        <table className={styles.detailTable} data-testid="job-import-set-tracking-table">
          <thead>
            <tr>
              <th>Set</th>
              <th>Trạng thái</th>
              <th align="right">Tổng bản ghi</th>
              <th>Version mới nhất (disk)</th>
              <th>Version đã apply</th>
              <th>Lịch sử</th>
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 ? (
              <tr>
                <td colSpan={6} className={styles.gridEmpty}>
                  {loading
                    ? 'Đang tải…'
                    : loadError
                      ? loadError
                      : searchQuery.trim()
                        ? 'Không tìm thấy set phù hợp.'
                        : 'Không có set CSV trên server (kiểm tra data/master/sets).'}
                </td>
              </tr>
            ) : null}
            {filtered.map((row: ImportSetTrackingItem) => {
              const isExpanded = expandedSet === row.setName;
              return (
                <React.Fragment key={row.setName}>
                  <tr>
                    <td>
                      <strong>{row.setName}</strong>
                      {row.description ? (
                        <>
                          <br />
                          <small style={{ color: '#64748b' }}>{row.description}</small>
                        </>
                      ) : null}
                    </td>
                    <td style={{ color: jobStatusColor(row.importStatus) }}>
                      {displayImportSetStatus(row.importStatus)}
                      {!row.isLatestVersionApplied && row.latestVersion ? (
                        <>
                          <br />
                          <small style={{ color: '#ca8a04' }}>Có version mới trên disk</small>
                        </>
                      ) : null}
                    </td>
                    <td align="right">
                      {row.totalRecords != null ? row.totalRecords.toLocaleString('vi-VN') : '—'}
                      {row.rowsUpserted != null && row.totalRecords != null && row.rowsUpserted !== row.totalRecords ? (
                        <>
                          <br />
                          <small style={{ color: '#64748b' }}>
                            upsert {row.rowsUpserted.toLocaleString('vi-VN')}
                          </small>
                        </>
                      ) : null}
                    </td>
                    <td>{formatVersionLabel(row.latestImportDate, row.latestVersion)}</td>
                    <td>{formatVersionLabel(row.appliedImportDate, row.appliedVersion)}</td>
                    <td>
                      <Button
                        type="button"
                        variant="secondary"
                        onClick={() => setExpandedSet(isExpanded ? null : row.setName)}
                        data-testid={`job-import-set-history-${row.setName}`}
                      >
                        {isExpanded ? 'Thu gọn' : `${row.versionHistory.length} version`}
                      </Button>
                      {row.lastRunId && onOpenRun ? (
                        <>
                          <br />
                          <button
                            type="button"
                            className={styles.linkButton}
                            onClick={() => onOpenRun(row.lastRunId!)}
                          >
                            Run gần nhất
                          </button>
                        </>
                      ) : null}
                    </td>
                  </tr>
                  {isExpanded ? (
                    <tr>
                      <td colSpan={6} style={{ background: '#f8fafc' }}>
                        <VersionHistoryTable item={row} />
                      </td>
                    </tr>
                  ) : null}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
      </div>
    </TableCard>
  );
};
