import React from 'react';
import { Button, SearchTextInput } from '../../ui';
import { formatListCountMeta } from './jobsListFilterUtils';
import styles from './JobInternalPage.module.css';

type Props = {
  searchQuery: string;
  onSearchChange: (value: string) => void;
  onSearch?: () => void;
  searchPlaceholder?: string;
  searchTestId?: string;
  onRefresh?: () => void;
  refreshDisabled?: boolean;
  refreshLabel?: string;
  extraActions?: React.ReactNode;
  totalCount: number;
  filteredCount?: number;
  loading?: boolean;
  itemLabel?: string;
  /** Ẩn meta count bên phải khi summary đã hiển thị ở header. */
  showCountMeta?: boolean;
};

export const JobsListToolbar: React.FC<Props> = ({
  searchQuery,
  onSearchChange,
  onSearch,
  searchPlaceholder = 'Tìm…',
  searchTestId,
  onRefresh,
  refreshDisabled,
  refreshLabel = 'Làm mới',
  extraActions,
  totalCount,
  filteredCount,
  loading = false,
  itemLabel = 'dòng',
  showCountMeta = true,
}) => {
  const shown = filteredCount ?? totalCount;
  return (
    <div className={styles.listToolbar}>
      <div className={styles.listToolbarSearch}>
        <SearchTextInput
          value={searchQuery}
          onChange={onSearchChange}
          onSearch={onSearch}
          placeholder={searchPlaceholder}
          testId={searchTestId}
        />
      </div>
      {onRefresh ? (
        <Button type="button" variant="secondary" onClick={onRefresh} disabled={refreshDisabled || loading}>
          {refreshLabel}
        </Button>
      ) : null}
      {extraActions}
      {showCountMeta ? (
        <span className={styles.listToolbarMeta}>
          {formatListCountMeta(loading, totalCount, shown, searchQuery, itemLabel)}
        </span>
      ) : null}
    </div>
  );
};

export default JobsListToolbar;
