import React from 'react';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import type {
  ExternalConnectorFieldMapping,
  ExternalConnectorPreviewResult,
} from '../../services/jobs';
import { CopyTextButton } from './CopyTextButton';
import {
  buildPreviewAiDebugBundle,
  buildPreviewResponseBundle,
  previewDetailFallbackNote,
} from './connectorDebugCopyUtils';
import styles from './ExternalConnectorPreviewPanel.module.css';

const STATUS_LABEL: Record<string, string> = {
  mapped: 'Đã map + import',
  pending: 'Preview only',
  skipped: 'Bỏ qua',
  warn: 'Cảnh báo',
  error: 'Lỗi',
};

export type ExternalConnectorPreviewPanelProps = {
  configKey?: string;
  preview: ExternalConnectorPreviewResult | null;
  loading: boolean;
  selectedDocumentKey: string | null;
  onSelectDocument: (documentKey: string) => void;
};

const formatJson = (text: string | null | undefined): string => {
  if (!text) return '';
  try {
    return JSON.stringify(JSON.parse(text), null, 2);
  } catch {
    return text;
  }
};

const MappingTable: React.FC<{ rows: ExternalConnectorFieldMapping[] }> = ({ rows }) => (
  <div className={styles.mappingWrap}>
    <table className={styles.mappingTable} data-testid="connector-preview-mapping-table">
      <thead>
        <tr>
          <th>FM field</th>
          <th>ERP field</th>
          <th>FM value</th>
          <th>ERP value</th>
          <th>Trạng thái</th>
        </tr>
      </thead>
      <tbody>
        {rows.map((row) => (
          <tr key={`${row.fmField}-${row.erpField}-${row.note ?? ''}`} data-status={row.status}>
            <td>
              <code>{row.fmField}</code>
            </td>
            <td>
              <code>{row.erpField}</code>
            </td>
            <td className={styles.valueCell}>{row.fmValue ?? '—'}</td>
            <td className={styles.valueCell}>{row.erpValue ?? '—'}</td>
            <td>
              <span className={`${styles.statusBadge} ${styles[`status_${row.status}`] ?? ''}`}>
                {STATUS_LABEL[row.status] ?? row.status}
              </span>
              {row.note ? <div className={styles.mapNote}>{row.note}</div> : null}
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  </div>
);

const JsonSection: React.FC<{
  label: string;
  json: string;
  testId: string;
  onCopyError: () => void;
  onCopyOk: () => void;
}> = ({ label, json, testId, onCopyError, onCopyOk }) => (
  <div>
    <div className={styles.sectionHeader}>
      <p className={styles.sectionLabel}>{label}</p>
      <CopyTextButton
        text={formatJson(json)}
        label="Copy JSON"
        testId={testId}
        onCopied={onCopyOk}
        onError={onCopyError}
      />
    </div>
    <pre className={styles.jsonBlock}>{formatJson(json)}</pre>
  </div>
);

export const ExternalConnectorPreviewPanel: React.FC<ExternalConnectorPreviewPanelProps> = ({
  configKey,
  preview,
  loading,
  selectedDocumentKey,
  onSelectDocument,
}) => {
  const toast = useAppToast();

  if (loading) {
    return (
      <p className={styles.loadingHint} data-testid="connector-preview-loading">
        Đang tải preview convert…
      </p>
    );
  }

  if (!preview) return null;

  const fallbackNote = previewDetailFallbackNote(preview);
  const hasIssues =
    !preview.success
    || preview.fieldMappings.some((m) => m.status === 'error' || m.status === 'warn')
    || Boolean(fallbackNote)
    || Boolean(preview.branchMap?.error);
  const aiDebugText = buildPreviewAiDebugBundle(preview, configKey);
  const responseText = buildPreviewResponseBundle(preview);

  const copyOk = () => toast.success('Đã copy — dán vào AI hoặc chat để phân tích');
  const copyErr = () => toast.error('Không copy được — kiểm tra quyền clipboard trình duyệt');

  return (
    <div className={styles.panel} data-testid="connector-preview-panel">
      <div className={styles.metaRow}>
        <span>
          <strong>{preview.voucherTypeLabel ?? 'Chứng từ'}</strong>
          {preview.success ? ' · Preview OK' : ' · Thất bại'}
          {preview.httpStatus ? ` · HTTP ${preview.httpStatus}` : ''}
          {preview.totalItems > 0 ? ` · total ${preview.totalItems}` : ''}
          {preview.elapsedMs ? ` · ${preview.elapsedMs} ms` : ''}
          {preview.sourceKind ? ` · nguồn: ${preview.sourceKind}` : ''}
        </span>
        {!preview.success && preview.message ? (
          <span className={styles.errorText}>{preview.message}</span>
        ) : null}
      </div>

      {preview.requestUrl ? (
        <p className={styles.requestUrl} data-testid="connector-preview-request-url">
          URL: <code>{preview.requestUrl}</code>
        </p>
      ) : null}

      <div className={styles.copyActions} data-testid="connector-preview-copy-actions">
        <CopyTextButton
          text={aiDebugText}
          label="Copy gói lỗi (AI)"
          testId="connector-preview-copy-ai-debug"
          onCopied={copyOk}
          onError={copyErr}
        />
        <CopyTextButton
          text={responseText}
          label="Copy response"
          disabled={!preview.fmSourceJson && !preview.erpPreviewJson && preview.searchItems.length === 0}
          testId="connector-preview-copy-response"
          onCopied={copyOk}
          onError={copyErr}
        />
        {hasIssues ? (
          <span className={styles.copyHint}>
            Gói lỗi gồm HTTP status, message, fallback detail, warnings/errors, JSON nguồn.
          </span>
        ) : null}
      </div>

      {fallbackNote ? (
        <div className={styles.fallbackBanner} data-testid="connector-preview-detail-fallback">
          <strong>Detail fallback:</strong> {fallbackNote}
        </div>
      ) : null}

      {preview.branchMap ? (
        <div
          className={`${styles.branchBanner} ${preview.branchMap.error ? styles.branchBannerErr : styles.branchBannerOk}`}
          data-testid="connector-preview-branch-map"
        >
          Chi nhánh:{' '}
          {preview.branchMap.error ? (
            preview.branchMap.error
          ) : (
            <>
              FM branchId={preview.branchMap.fmBranchId ?? '—'} →{' '}
              <strong>{preview.branchMap.companyCode}</strong>
              {preview.branchMap.companyName ? ` (${preview.branchMap.companyName})` : ''}
              {preview.branchMap.matchedBy ? ` · matchedBy=${preview.branchMap.matchedBy}` : ''}
            </>
          )}
        </div>
      ) : null}

      {preview.searchItems.length > 0 ? (
        <div className={styles.searchList}>
          <p className={styles.sectionLabel}>Kết quả search — chọn chứng từ để preview convert</p>
          <ul className={styles.docList} data-testid="connector-preview-search-list">
            {preview.searchItems.map((item) => (
              <li key={item.documentKey}>
                <button
                  type="button"
                  className={`${styles.docBtn} ${
                    selectedDocumentKey === item.documentKey ? styles.docBtnActive : ''
                  }`}
                  onClick={() => onSelectDocument(item.documentKey)}
                  data-testid={`connector-preview-doc-${item.documentKey}`}
                >
                  {item.label}
                </button>
              </li>
            ))}
          </ul>
        </div>
      ) : null}

      {preview.fieldMappings.length > 0 ? (
        <>
          <p className={styles.sectionLabel}>
            Map field → ERP preview
            {preview.selectedDocumentKey ? ` · ${preview.selectedDocumentKey}` : ''}
          </p>
          <MappingTable rows={preview.fieldMappings} />
        </>
      ) : null}

      {(preview.fmSourceJson || preview.erpPreviewJson) && (
        <div className={styles.jsonGrid}>
          {preview.fmSourceJson ? (
            <JsonSection
              label="FM source (detail/search)"
              json={preview.fmSourceJson}
              testId="connector-preview-copy-fm-json"
              onCopyOk={copyOk}
              onCopyError={copyErr}
            />
          ) : null}
          {preview.erpPreviewJson ? (
            <JsonSection
              label="ERP preview (sau convert)"
              json={preview.erpPreviewJson}
              testId="connector-preview-copy-erp-json"
              onCopyOk={copyOk}
              onCopyError={copyErr}
            />
          ) : null}
        </div>
      )}
    </div>
  );
};

export default ExternalConnectorPreviewPanel;
