import React from 'react';
import { Link } from 'react-router-dom';
import {
  companyService,
  getActiveCompanyId,
  setActiveCompanyId,
  useAppToast,
  useNavTitle,
  type ActiveCompanyItem,
} from '@linm-soft-org/linm-web-common-components';
import { Button } from '../../ui';
import {
  jobsService,
  type ExternalSyncVoucherRenumberPreview,
} from '../../services/jobs';
import styles from './JobInternalPage.module.css';

const ExternalSyncVoucherRenumberPage: React.FC = () => {
  useNavTitle('Đánh lại số chứng từ POS');
  const toast = useAppToast();

  const [companies, setCompanies] = React.useState<ActiveCompanyItem[]>([]);
  const [companyCode, setCompanyCode] = React.useState('');
  const [fromDate, setFromDate] = React.useState('');
  const [toDate, setToDate] = React.useState('');
  const [voucherCode, setVoucherCode] = React.useState('');
  const [preview, setPreview] = React.useState<ExternalSyncVoucherRenumberPreview | null>(null);
  const [loadingPreview, setLoadingPreview] = React.useState(false);
  const [running, setRunning] = React.useState(false);

  React.useEffect(() => {
    companyService
      .getActiveList()
      .then((list) => {
        setCompanies(list);
        const active = getActiveCompanyId();
        const match = list.find((c) => c.id === active);
        const initial = match?.id ?? list[0]?.id ?? '';
        if (initial) {
          setCompanyCode(initial);
          setActiveCompanyId(initial);
        }
      })
      .catch((e: Error) => toast.error(e.message));
  }, [toast]);

  const applyTenant = React.useCallback((code: string) => {
    const trimmed = code.trim();
    setCompanyCode(trimmed);
    if (trimmed) setActiveCompanyId(trimmed);
  }, []);

  const loadPreview = React.useCallback(() => {
    if (!companyCode.trim()) {
      toast.warning('Chọn đơn vị cơ sở trước khi xem trước.');
      return;
    }
    setActiveCompanyId(companyCode.trim());
    setLoadingPreview(true);
    jobsService
      .getExternalSyncVoucherRenumberPreview({
        fromDate: fromDate || null,
        toDate: toDate || null,
        voucherCode: voucherCode.trim() || null,
      })
      .then(setPreview)
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoadingPreview(false));
  }, [companyCode, fromDate, toDate, voucherCode, toast]);

  React.useEffect(() => {
    if (companyCode) loadPreview();
  }, [companyCode, loadPreview]);

  const handleRun = React.useCallback(() => {
    if (!companyCode.trim()) {
      toast.warning('Chọn đơn vị cơ sở.');
      return;
    }
    if (!preview?.invoiceCount && !preview?.receiptCount) {
      toast.warning('Không có HĐ/PT cần đánh lại trong bộ lọc.');
      return;
    }
    const range =
      fromDate || toDate
        ? `\nKhoảng ngày HĐ: ${fromDate || '…'} → ${toDate || '…'}`
        : '';
    const codeLine = voucherCode.trim() ? `\nMã lọc: ${voucherCode.trim()}` : '';
    const ok = window.confirm(
      `Đánh lại số ${preview.invoiceCount.toLocaleString('vi-VN')} HĐ · ` +
        `${preview.receiptCount.toLocaleString('vi-VN')} PT trên đơn vị ${companyCode}?` +
        range +
        codeLine +
        '\n\nKhông đổi số liệu — sau đó enqueue ghi sổ lại theo mã mới.',
    );
    if (!ok) return;

    setActiveCompanyId(companyCode.trim());
    setRunning(true);
    jobsService
      .triggerExternalSyncVoucherRenumber({
        fromDate: fromDate || null,
        toDate: toDate || null,
        voucherCode: voucherCode.trim() || null,
        repostAfterRenumber: true,
      })
      .then((result) => {
        toast.success(
          `Đã đánh lại ${result.invoicesRenumbered.toLocaleString('vi-VN')} HĐ · ` +
            `${result.receiptsRenumbered.toLocaleString('vi-VN')} PT` +
            (result.postEventsEnqueued
              ? ` — enqueue ghi sổ ${result.postEventsEnqueued.toLocaleString('vi-VN')}`
              : '') +
            (result.firstPostEventId ? ` (event ${result.firstPostEventId.slice(0, 8)}…)` : ''),
        );
        loadPreview();
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setRunning(false));
  }, [companyCode, fromDate, toDate, voucherCode, preview, toast, loadPreview]);

  const companyLabel =
    companies.find((c) => c.id === companyCode)?.shortName ||
    companies.find((c) => c.id === companyCode)?.name ||
    companyCode;

  return (
    <div data-testid="external-sync-voucher-renumber-page">
      <p className={styles.listHint} style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs/external-runs">Theo dõi sync REVA</Link>
        {' · '}
        <Link to="/admin/jobs">Hub job</Link>
      </p>

      <div
        style={{
          padding: '16px 20px',
          border: '1px solid #e2e8f0',
          borderRadius: 8,
          background: '#f8fafc',
          maxWidth: 720,
        }}
        data-testid="voucher-renumber-panel"
      >
        <h2 style={{ margin: '0 0 8px', fontSize: 18 }}>Đánh lại số chứng từ POS (REVA FM)</h2>
        <p style={{ margin: '0 0 16px', color: '#64748b', fontSize: 13 }}>
          HĐ/PT còn placeholder <code>FM-HD-*</code> hoặc mã trùng legacy → gán <code>INV-*</code> /{' '}
          <code>PT-*</code> tuần tự theo ngày chứng từ. Tự chạy sau mỗi run sync{' '}
          <code>reva-fm-hoa-don</code>; trang này dùng khi cần chạy thủ công theo khoảng thời gian.
        </p>

        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12, marginBottom: 12, alignItems: 'center' }}>
          <label style={{ fontSize: 13, minWidth: 200 }}>
            Đơn vị cơ sở <span style={{ color: '#dc2626' }}>*</span>
            <select
              value={companyCode}
              onChange={(e) => applyTenant(e.target.value)}
              style={{ display: 'block', marginTop: 4, minWidth: 200 }}
              data-testid="voucher-renumber-company"
            >
              <option value="">— Chọn —</option>
              {companies.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.id}
                  {c.shortName || c.name ? ` — ${c.shortName ?? c.name}` : ''}
                </option>
              ))}
            </select>
          </label>
          <label style={{ fontSize: 13 }}>
            Từ ngày
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
              style={{ display: 'block', marginTop: 4 }}
              data-testid="voucher-renumber-from-date"
            />
          </label>
          <label style={{ fontSize: 13 }}>
            Đến ngày
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
              style={{ display: 'block', marginTop: 4 }}
              data-testid="voucher-renumber-to-date"
            />
          </label>
          <label style={{ fontSize: 13, flex: '1 1 180px' }}>
            Mã chứng từ (tùy chọn)
            <input
              type="text"
              value={voucherCode}
              onChange={(e) => setVoucherCode(e.target.value)}
              placeholder="INV-… / FM-HD-…"
              style={{ display: 'block', marginTop: 4, width: '100%' }}
              data-testid="voucher-renumber-code"
            />
          </label>
        </div>

        {companyCode ? (
          <p style={{ margin: '0 0 12px', fontSize: 13, color: '#475569' }}>
            Tenant API: <code>X-Company-Id: {companyCode}</code>
            {companyLabel !== companyCode ? ` (${companyLabel})` : ''}
          </p>
        ) : (
          <p style={{ margin: '0 0 12px', fontSize: 13, color: '#b45309' }}>
            Chọn đơn vị — API yêu cầu header <code>X-Company-Id</code> (mã công ty, không phải Guid nội bộ).
          </p>
        )}

        {loadingPreview ? (
          <p style={{ fontSize: 13 }}>Đang đếm…</p>
        ) : preview ? (
          <p style={{ margin: '0 0 12px', fontSize: 13 }}>
            Cần đánh lại: <strong>{preview.invoiceCount.toLocaleString('vi-VN')}</strong> HĐ ·{' '}
            <strong>{preview.receiptCount.toLocaleString('vi-VN')}</strong> PT
            {preview.sampleInvoiceCodes.length > 0
              ? ` — HĐ ví dụ: ${preview.sampleInvoiceCodes.slice(0, 3).join(', ')}`
              : ''}
            {preview.sampleReceiptCodes.length > 0
              ? ` — PT ví dụ: ${preview.sampleReceiptCodes.slice(0, 3).join(', ')}`
              : ''}
          </p>
        ) : null}

        <div style={{ display: 'flex', gap: 8 }}>
          <Button
            type="button"
            variant="secondary"
            onClick={loadPreview}
            disabled={loadingPreview || running || !companyCode}
            data-testid="voucher-renumber-refresh"
          >
            Xem trước
          </Button>
          <Button
            type="button"
            onClick={handleRun}
            disabled={
              running ||
              loadingPreview ||
              !companyCode ||
              (!preview?.invoiceCount && !preview?.receiptCount)
            }
            data-testid="voucher-renumber-run"
          >
            {running ? 'Đang đánh lại…' : 'Đánh lại số + ghi sổ'}
          </Button>
        </div>
      </div>
    </div>
  );
};

export default ExternalSyncVoucherRenumberPage;
