export type ScheduleRecurrenceKind = 'none' | 'daily' | 'weekly' | 'monthly' | 'yearly';

export interface PlatformJobScheduleRecurrence {
  kind: ScheduleRecurrenceKind;
  hour: number;
  minute: number;
  /** ISO weekday 1=Mon … 7=Sun */
  daysOfWeek?: number[];
  dayOfMonth?: number;
  lastDayOfMonth?: boolean;
  /** 1–12 for yearly */
  month?: number;
}

export interface PlatformJobScheduleSeedFields {
  importSets?: string[];
  forceReImport?: boolean;
  defaultCompanyId?: string;
  connectorKeys?: string[];
}

export interface PlatformJobScheduleOptions extends PlatformJobScheduleSeedFields {
  scheduleTimezoneId?: string;
  recurrence?: PlatformJobScheduleRecurrence;
}

export const DEFAULT_SCHEDULE_TIMEZONE = 'Asia/Ho_Chi_Minh';

export const JOB_SCHEDULE_TIMEZONES: { id: string; label: string }[] = [
  { id: 'Asia/Ho_Chi_Minh', label: 'Việt Nam (Asia/Ho_Chi_Minh)' },
  { id: 'Asia/Bangkok', label: 'Bangkok (Asia/Bangkok)' },
  { id: 'Asia/Singapore', label: 'Singapore (Asia/Singapore)' },
  { id: 'Asia/Tokyo', label: 'Tokyo (Asia/Tokyo)' },
  { id: 'UTC', label: 'UTC' },
];

export const WEEKDAY_OPTIONS: { value: number; label: string }[] = [
  { value: 1, label: 'Thứ 2' },
  { value: 2, label: 'Thứ 3' },
  { value: 3, label: 'Thứ 4' },
  { value: 4, label: 'Thứ 5' },
  { value: 5, label: 'Thứ 6' },
  { value: 6, label: 'Thứ 7' },
  { value: 7, label: 'Chủ nhật' },
];

export const defaultRecurrence = (): PlatformJobScheduleRecurrence => ({
  kind: 'none',
  hour: 2,
  minute: 0,
});

export const parseScheduleOptions = (json?: string | null): PlatformJobScheduleOptions => {
  const base: PlatformJobScheduleOptions = {
    importSets: ['REVA_*'],
    defaultCompanyId: 'LINM',
    forceReImport: false,
    scheduleTimezoneId: DEFAULT_SCHEDULE_TIMEZONE,
    recurrence: defaultRecurrence(),
  };
  if (!json) return base;
  try {
    const parsed = JSON.parse(json) as PlatformJobScheduleOptions;
    return {
      ...base,
      ...parsed,
      recurrence: parsed.recurrence
        ? { ...defaultRecurrence(), ...parsed.recurrence }
        : defaultRecurrence(),
    };
  } catch {
    return base;
  }
};

export const buildScheduleOptionsJson = (opts: PlatformJobScheduleOptions): string => {
  const payload: PlatformJobScheduleOptions = {
    ...(opts.importSets?.length ? { importSets: opts.importSets.filter(Boolean) } : {}),
    ...(opts.defaultCompanyId ? { defaultCompanyId: opts.defaultCompanyId.trim() } : {}),
    ...(opts.forceReImport ? { forceReImport: true } : {}),
    ...(opts.connectorKeys?.length ? { connectorKeys: opts.connectorKeys.filter(Boolean) } : {}),
    scheduleTimezoneId: opts.scheduleTimezoneId?.trim() || DEFAULT_SCHEDULE_TIMEZONE,
    recurrence: opts.recurrence ?? defaultRecurrence(),
  };
  return JSON.stringify(payload);
};

export const formatRecurrenceSummary = (json?: string | null): string => {
  const opts = parseScheduleOptions(json);
  const r = opts.recurrence;
  if (!r || r.kind === 'none') return '—';

  const tz = opts.scheduleTimezoneId ?? DEFAULT_SCHEDULE_TIMEZONE;
  const time = `${String(r.hour).padStart(2, '0')}:${String(r.minute).padStart(2, '0')}`;

  switch (r.kind) {
    case 'daily':
      return `Hàng ngày ${time} (${tz})`;
    case 'weekly': {
      const days = (r.daysOfWeek ?? [])
        .map((d) => WEEKDAY_OPTIONS.find((w) => w.value === d)?.label ?? String(d))
        .join(', ');
      return days ? `Hàng tuần ${days} ${time} (${tz})` : '—';
    }
    case 'monthly':
      return r.lastDayOfMonth
        ? `Cuối tháng ${time} (${tz})`
        : `Ngày ${r.dayOfMonth ?? '?'} hàng tháng ${time} (${tz})`;
    case 'yearly':
      return r.lastDayOfMonth
        ? `Cuối tháng ${r.month} hàng năm ${time} (${tz})`
        : `Hàng năm ${r.dayOfMonth}/${r.month} ${time} (${tz})`;
    default:
      return '—';
  }
};

export const parseTimeInput = (value: string): { hour: number; minute: number } => {
  const [h, m] = value.split(':');
  const hour = Math.min(23, Math.max(0, Number(h) || 0));
  const minute = Math.min(59, Math.max(0, Number(m) || 0));
  return { hour, minute };
};

export const formatTimeInput = (hour: number, minute: number): string =>
  `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
