/** FeaturePackage AllowedCompanyScopeJson — mirrors Auth CompanyScopeConfig. */

export type CompanyScopeMode = 'own' | 'listed' | 'all';

export interface CompanyScopeConfig {
  mode: CompanyScopeMode;
  companyIds: string[];
}

export function parseCompanyScopeJson(json?: string | null): CompanyScopeConfig {
  if (!json?.trim()) return { mode: 'own', companyIds: [] };
  try {
    const raw = JSON.parse(json) as { mode?: string; companyIds?: string[] };
    const mode = (raw.mode?.trim().toLowerCase() ?? 'own') as CompanyScopeMode;
    if (mode === 'all') return { mode: 'all', companyIds: [] };
    if (mode === 'listed') {
      return {
        mode: 'listed',
        companyIds: (raw.companyIds ?? []).map(String).filter(Boolean),
      };
    }
    return { mode: 'own', companyIds: [] };
  } catch {
    return { mode: 'own', companyIds: [] };
  }
}

export function buildCompanyScopeJson(mode: CompanyScopeMode, companyIds: string[]): string {
  return JSON.stringify({
    mode,
    companyIds: mode === 'listed' ? companyIds : [],
  });
}

export function mergeAllowedCompanyIdsFromPackages(
  packages: Array<{ allowedCompanyScopeJson?: string | null }>,
  homeCompanyId?: string | null,
): string[] {
  const ids = new Set<string>();
  let canViewAll = false;

  for (const pkg of packages) {
    const scope = parseCompanyScopeJson(pkg.allowedCompanyScopeJson);
    if (scope.mode === 'all') {
      canViewAll = true;
      break;
    }
    if (scope.mode === 'listed') {
      scope.companyIds.forEach((id) => ids.add(id));
    }
  }

  if (canViewAll) return homeCompanyId ? [homeCompanyId] : [];
  if (homeCompanyId) ids.add(homeCompanyId);
  return [...ids];
}

export const USER_SCOPE_PACKAGE_PREFIX = 'SCOPE-';

export function userScopePackageCode(username: string): string {
  const safe = username.replace(/[^a-zA-Z0-9_-]/g, '').toUpperCase().slice(0, 24);
  return `${USER_SCOPE_PACKAGE_PREFIX}${safe || 'USER'}`;
}
