import React from 'react';
import { Link } from 'react-router-dom';
import type { PlatformEventListItem } from '../../../services/jobs';
import { JobProgressBar } from './JobProgressBar';
import { displayJobStatus, displayLinkedRunStatus, jobStatusColor } from '../jobStatusDisplay';
import { resolveEventJobStatus, resolveRunJobStatus } from '../platformJobStatus';
import styles from '../JobInternalPage.module.css';

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

/** External sync run page vs master CSV import run (Job nội bộ). */
export const usesExternalSyncRunPage = (eventType: string, importSource?: string | null): boolean =>
  eventType.startsWith('DataSync.External') ||
  (eventType === 'Document.PostImportRequested' && importSource === 'DataSyncExternal');

export const resolvePlatformEventRunHref = (
  eventType: string,
  runId: string,
  importSource?: string | null,
): string => {
  if (usesExternalSyncRunPage(eventType, importSource))
    return `/admin/jobs/external-runs?runId=${encodeURIComponent(runId)}`;
  return `/admin/jobs/internal?tab=import&runId=${encodeURIComponent(runId)}`;
};

export const buildPlatformEventSearchText = (e: PlatformEventListItem): string =>
  [
    e.eventId,
    e.eventType,
    e.eventDisplayName ?? '',
    e.contextKey ?? '',
    e.contextDetail ?? '',
    e.runId ?? '',
    e.jobStatus ?? e.processingStatus,
    e.runJobStatus ?? e.runStatus ?? '',
    e.lastError ?? '',
    e.correlationId ?? '',
    formatDate(e.createdAt),
    String(e.progressPercent ?? ''),
  ].join(' ');

export type JobEventsTableProps = {
  events: PlatformEventListItem[];
  selectedEventId: string | null;
  onSelectEvent: (eventId: string) => void;
  onRunLinkClick?: (event: React.MouseEvent) => void;
};

export const JobEventsTable: React.FC<JobEventsTableProps> = ({
  events,
  selectedEventId,
  onSelectEvent,
  onRunLinkClick,
}) => (
  <table className={styles.eventsTable}>
    <thead>
      <tr>
        <th align="left">Loại event</th>
        <th align="left">Khóa / ngữ cảnh</th>
        <th align="left">Run ID</th>
        <th align="left">Trạng thái</th>
        <th align="left">Tiến độ</th>
        <th align="left">Run</th>
        <th align="left">Tạo</th>
      </tr>
    </thead>
    <tbody>
      {events.map((e) => (
        <tr
          key={e.eventId}
          onClick={() => onSelectEvent(e.eventId)}
          className={`${styles.eventRow} ${selectedEventId === e.eventId ? styles.eventRowSelected : ''}`}
        >
          <td>
            <div style={{ fontWeight: 600, fontSize: 13 }}>{e.eventDisplayName ?? e.eventType}</div>
            <div className={styles.gridSub} style={{ marginTop: 2 }}>
              {e.eventType}
            </div>
          </td>
          <td style={{ fontSize: 12, maxWidth: 220 }}>
            {e.contextKey ? (
              <div className={styles.gridMono} style={{ fontWeight: 600 }}>
                {e.contextKey}
              </div>
            ) : null}
            {e.contextDetail ? (
              <div style={{ color: '#64748b', marginTop: e.contextKey ? 2 : 0 }}>{e.contextDetail}</div>
            ) : (
              !e.contextKey ? '—' : null
            )}
          </td>
          <td onClick={onRunLinkClick}>
            {e.runId ? (
              <Link
                to={resolvePlatformEventRunHref(e.eventType, e.runId, e.importSource)}
                className={styles.linkButton}
                onClick={(ev) => ev.stopPropagation()}
                title={e.runId}
              >
                {e.runId.slice(0, 8)}…
              </Link>
            ) : (
              '—'
            )}
          </td>
          <td style={{ color: jobStatusColor(resolveEventJobStatus(e)) }}>
            {displayJobStatus(resolveEventJobStatus(e))}
          </td>
          <td>
            <JobProgressBar
              percent={e.progressPercent}
              done={e.documentsDone}
              total={e.documentsTotal}
              unit={e.progressUnit}
              compact
            />
          </td>
          <td style={{ fontSize: 12, color: jobStatusColor(resolveRunJobStatus(e) ?? '') }}>
            {resolveRunJobStatus(e) ? displayLinkedRunStatus(resolveRunJobStatus(e)!) : '—'}
          </td>
          <td style={{ fontSize: 12, whiteSpace: 'nowrap' }}>{formatDate(e.createdAt)}</td>
        </tr>
      ))}
    </tbody>
  </table>
);
