import React from 'react';
import { Link } from 'react-router-dom';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Button, Modal } from '../../../ui';
import { jobsService, type CsvImportSetListItem, type ImportSetsReImportResult } from '../../../services/jobs';
import styles from '../JobInternalPage.module.css';

export type JobImportSetsReImportModalProps = {
  isOpen: boolean;
  onClose: () => void;
  /** Pre-select set names when opened from tracking row. */
  initialSelectedSets?: string[];
  onSuccess?: (result: ImportSetsReImportResult) => void;
};

export const JobImportSetsReImportModal: React.FC<JobImportSetsReImportModalProps> = ({
  isOpen,
  onClose,
  initialSelectedSets,
  onSuccess,
}) => {
  const toast = useAppToast();
  const [loading, setLoading] = React.useState(false);
  const [submitting, setSubmitting] = React.useState(false);
  const [sets, setSets] = React.useState<CsvImportSetListItem[]>([]);
  const [selected, setSelected] = React.useState<Set<string>>(new Set());
  const [cleanBeforeImport, setCleanBeforeImport] = React.useState(true);
  const [filter, setFilter] = React.useState('');

  React.useEffect(() => {
    if (!isOpen) return;
    setCleanBeforeImport(true);
    setFilter('');
    setLoading(true);
    jobsService
      .getImportSetConfigs()
      .then((rows) => {
        const sorted = [...rows].sort((a, b) => a.sortOrder - b.sortOrder || a.setName.localeCompare(b.setName));
        setSets(sorted);
        const preselect = new Set(initialSelectedSets?.filter(Boolean) ?? []);
        if (preselect.size === 0) {
          sorted.filter((r) => r.hasDirectory && r.isEnabled).forEach((r) => preselect.add(r.setName));
        } else {
          sorted.forEach((r) => {
            if (!preselect.has(r.setName)) return;
            if (!r.hasDirectory) preselect.delete(r.setName);
          });
        }
        setSelected(preselect);
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [isOpen, initialSelectedSets, toast]);

  const filtered = React.useMemo(() => {
    const q = filter.trim().toLowerCase();
    if (!q) return sets;
    return sets.filter(
      (r) =>
        r.setName.toLowerCase().includes(q) ||
        (r.description ?? '').toLowerCase().includes(q) ||
        r.catalogs.some((c) => c.toLowerCase().includes(q)),
    );
  }, [sets, filter]);

  const selectable = filtered.filter((r) => r.hasDirectory);
  const allSelectableSelected =
    selectable.length > 0 && selectable.every((r) => selected.has(r.setName));

  const toggleSet = (setName: string, enabled: boolean) => {
    if (!enabled) return;
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(setName)) next.delete(setName);
      else next.add(setName);
      return next;
    });
  };

  const toggleSelectAll = () => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (allSelectableSelected) {
        selectable.forEach((r) => next.delete(r.setName));
      } else {
        selectable.forEach((r) => next.add(r.setName));
      }
      return next;
    });
  };

  const submit = async () => {
    const names = [...selected];
    if (names.length === 0) {
      toast.error('Chọn ít nhất một import set.');
      return;
    }
    setSubmitting(true);
    try {
      const result = await jobsService.reImportSets({ sets: names, cleanBeforeImport });
      const deleted =
        result.rowsDeleted > 0 ? ` · đã xóa ${result.rowsDeleted.toLocaleString('vi-VN')} bản ghi cũ` : '';
      toast.success(`Đã enqueue re-import (${result.sets.length} set)${deleted}`);
      onSuccess?.(result);
      onClose();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Re-import thất bại');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Re-import CSV master set"
      size="lg"
      fillContent
      stacked
    >
      <div
        style={{ display: 'flex', flexDirection: 'column', gap: 12, minHeight: 320 }}
        data-testid="job-import-sets-reimport-modal"
      >
        <p style={{ margin: 0, fontSize: 13, color: '#475569', lineHeight: 1.5 }}>
          Chọn set trong <code>data/master/sets</code> · enqueue job import bất đồng bộ. Khác với{' '}
          <strong>Force re-import</strong> trong cấu hình lịch (chỉ bỏ qua manifest stamp).
        </p>

        <label style={{ display: 'flex', gap: 8, alignItems: 'flex-start', cursor: 'pointer' }}>
          <input
            type="checkbox"
            checked={cleanBeforeImport}
            onChange={(e) => setCleanBeforeImport(e.target.checked)}
            data-testid="job-import-sets-clean-before"
          />
          <span style={{ fontSize: 13 }}>
            <strong>Xóa dữ liệu cũ trước khi import</strong> (cleanBeforeImport) — xóa bản ghi{' '}
            <code>csv-import</code> theo catalog set + clear fingerprint · khuyến nghị khi sửa CSV /
            dọn trùng mã (vd. <code>reva-materials</code>).
          </span>
        </label>

        <input
          type="search"
          placeholder="Lọc set…"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          style={{ maxWidth: 360, padding: '6px 10px', borderRadius: 6, border: '1px solid #cbd5e1' }}
          data-testid="job-import-sets-reimport-filter"
        />

        {loading ? (
          <p className={styles.gridLoading}>Đang tải danh sách set…</p>
        ) : filtered.length === 0 ? (
          <p className={styles.gridEmpty}>Không có import set phù hợp.</p>
        ) : (
          <div
            className={styles.gridWrap}
            style={{ maxHeight: 360, overflow: 'auto', border: '1px solid #e2e8f0', borderRadius: 8 }}
          >
            <table className={styles.detailTable} data-testid="job-import-sets-reimport-table">
              <thead>
                <tr>
                  <th style={{ width: 40 }}>
                    <input
                      type="checkbox"
                      checked={allSelectableSelected && selectable.length > 0}
                      disabled={selectable.length === 0}
                      onChange={toggleSelectAll}
                      aria-label="Chọn tất cả"
                    />
                  </th>
                  <th>Set</th>
                  <th>Manifest</th>
                  <th>Catalog</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((row) => {
                  const disabled = !row.hasDirectory;
                  const checked = selected.has(row.setName);
                  return (
                    <tr key={row.setName} data-testid={`job-import-set-row-${row.setName}`}>
                      <td>
                        <input
                          type="checkbox"
                          checked={checked}
                          disabled={disabled}
                          onChange={() => toggleSet(row.setName, !disabled)}
                        />
                      </td>
                      <td>
                        <div style={{ fontWeight: 500 }}>{row.setName}</div>
                        {row.description ? (
                          <div className={styles.gridSub}>{row.description}</div>
                        ) : null}
                        {!row.hasDirectory ? (
                          <div className={styles.gridSub} style={{ color: '#b45309' }}>
                            Thiếu thư mục CSV trên server
                          </div>
                        ) : null}
                      </td>
                      <td style={{ fontSize: 12 }}>
                        {row.importDate ?? '—'}
                        {row.importVersion ? ` · v${row.importVersion}` : ''}
                      </td>
                      <td style={{ fontSize: 11, maxWidth: 200 }}>
                        {row.catalogs.length > 0 ? row.catalogs.join(', ') : '—'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        <p style={{ margin: 0, fontSize: 12, color: '#64748b' }}>
          Theo dõi tiến độ:{' '}
          <Link to="/admin/jobs/internal?tab=import" onClick={onClose}>
            Job nội bộ → Lượt import
          </Link>
          {' · '}
          <Link to="/admin/jobs/internal?tab=sets" onClick={onClose}>
            Theo dõi set CSV
          </Link>
        </p>

        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginTop: 'auto', paddingTop: 8 }}>
          <Button
            type="button"
            onClick={submit}
            disabled={loading || submitting || selected.size === 0}
            data-testid="job-import-sets-reimport-submit"
          >
            {submitting ? 'Đang enqueue…' : `Re-import (${selected.size} set)`}
          </Button>
          <Button type="button" variant="secondary" onClick={onClose} disabled={submitting}>
            Hủy
          </Button>
        </div>
      </div>
    </Modal>
  );
};
