import type { PagedResult } from './jobsModels';

/** ERP `PaginatedResult` wire shape uses `totalCount`; Auth uses `total`. */
type WirePagedResult<T> = {
  items?: T[];
  total?: number;
  totalCount?: number;
  page?: number;
  pageSize?: number;
};

export function normalizePagedResult<T>(raw: WirePagedResult<T>): PagedResult<T> {
  const items = raw.items ?? [];
  const total = raw.total ?? raw.totalCount ?? items.length;
  return {
    items,
    total,
    page: raw.page ?? 1,
    pageSize: raw.pageSize ?? 20,
  };
}
