import React from 'react';
import { Link } from 'react-router-dom';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Button } from '../../../ui';
import { jobsService, type PlatformEventDetail } from '../../../services/jobs';
import { JobProgressBar } from './JobProgressBar';
import { JobEventSkipInfo } from './JobEventSkipInfo';
import { resolvePlatformEventRunHref, usesExternalSyncRunPage } from './JobEventsTable';
import {
  JobDetailErrorBlock,
  JobDetailMetaGrid,
  JobDetailMonoId,
  JobDetailSection,
  formatJobDate,
  type JobDetailMetaItem,
} from './JobDetailMetaGrid';
import styles from '../JobInternalPage.module.css';
import {
  displayJobStatus,
  displayLinkedRunStatus,
  jobStatusColor,
  resolveRunStatusFromEvent,
} from '../jobStatusDisplay';
import { PlatformJobStatus, resolveEventJobStatus } from '../platformJobStatus';

const FAIL_STATUSES = new Set(['Failed', 'DeadLetter']);
const REQUEUE_STATUSES = new Set(['Failed', 'DeadLetter', 'Cancelled']);

const progressCaption = (detail: PlatformEventDetail): string => {
  const unit = detail.progressUnit === 'sets' ? 'set' : detail.progressUnit === 'documents' ? 'chứng từ' : 'mục';
  if (detail.documentsDone != null && detail.documentsTotal != null) {
    return `Tiến độ: ${detail.documentsDone}/${detail.documentsTotal} ${unit}`;
  }
  if (detail.progressPercent != null) {
    return `Tiến độ: ${detail.progressPercent}%`;
  }
  return 'Tiến độ: —';
};

export type JobEventDetailPanelProps = {
  detail: PlatformEventDetail;
  onOpenImportRun: (runId: string) => void;
  onRequeued?: () => void;
};

export const JobEventDetailPanel: React.FC<JobEventDetailPanelProps> = ({
  detail,
  onOpenImportRun,
  onRequeued,
}) => {
  const toast = useAppToast();
  const [requeuing, setRequeuing] = React.useState(false);
  const canRequeue = REQUEUE_STATUSES.has(detail.processingStatus);

  const handleRequeue = () => {
    if (!window.confirm('Đưa event vào hàng đợi lại (Pending)? Attempt sẽ reset về 0.')) return;
    setRequeuing(true);
    jobsService
      .requeueEvent(detail.eventId, true)
      .then((r) => {
        toast.success(`Đã requeue — ${r.jobStatus}`);
        onRequeued?.();
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setRequeuing(false));
  };
  const effectiveRunStatus = resolveRunStatusFromEvent(detail);
  const showFailBlock =
    detail.lastError &&
    (FAIL_STATUSES.has(detail.processingStatus) ||
      resolveEventJobStatus(detail) === PlatformJobStatus.Running);

  const overviewItems: JobDetailMetaItem[] = [
    {
      label: 'Loại event',
      value: detail.eventDisplayName ? (
        <>
          <strong>{detail.eventDisplayName}</strong>
          <div className={styles.gridSub} style={{ marginTop: 4 }}>
            {detail.eventType}
          </div>
        </>
      ) : (
        detail.eventType
      ),
      fullWidth: true,
    },
    ...(detail.contextKey || detail.contextDetail
      ? [
          {
            label: 'Khóa / ngữ cảnh',
            value: (
              <>
                {detail.contextKey ? <div className={styles.gridMono}>{detail.contextKey}</div> : null}
                {detail.contextDetail ? (
                  <div style={{ color: '#64748b', marginTop: detail.contextKey ? 4 : 0 }}>
                    {detail.contextDetail}
                  </div>
                ) : null}
              </>
            ),
            fullWidth: true,
          } satisfies JobDetailMetaItem,
        ]
      : []),
    {
      label: 'Trạng thái event',
      value: (
        <span style={{ color: jobStatusColor(resolveEventJobStatus(detail)) }}>
          {displayJobStatus(resolveEventJobStatus(detail))}
        </span>
      ),
    },
    { label: 'Attempt', value: `${detail.attemptCount}/${detail.maxAttempts}` },
    { label: 'Tier', value: detail.jobTier },
    { label: 'Direction', value: detail.direction },
    ...(effectiveRunStatus
      ? [
          {
            label: 'Trạng thái run',
            value: (
              <span style={{ color: jobStatusColor(effectiveRunStatus) }}>
                {displayLinkedRunStatus(effectiveRunStatus)}
              </span>
            ),
          } satisfies JobDetailMetaItem,
        ]
      : []),
    ...(detail.runStatus && detail.runStatus !== effectiveRunStatus
      ? [{ label: 'Run status (DB)', value: detail.runStatus, mono: true } satisfies JobDetailMetaItem]
      : []),
  ];

  const sourceItems: JobDetailMetaItem[] = [
    { label: 'Company ID', value: detail.companyId, mono: true },
    { label: 'Source document type', value: detail.sourceDocumentType ?? '—' },
    { label: 'Source document ID', value: detail.sourceDocumentId ?? '—', mono: true },
    { label: 'Period job run ID', value: detail.periodJobRunId ?? '—', mono: true },
  ];

  const trackingItems: JobDetailMetaItem[] = [
    { label: 'Correlation ID', value: detail.correlationId ?? '—', mono: true, fullWidth: true },
    { label: 'Idempotency key', value: detail.idempotencyKey, mono: true, fullWidth: true },
    { label: 'Locked by', value: detail.lockedBy ?? '—', mono: true },
    {
      label: 'Run ID',
      value: detail.runId ? (
        usesExternalSyncRunPage(detail.eventType, detail.importSource) ? (
          <Link to={resolvePlatformEventRunHref(detail.eventType, detail.runId, detail.importSource)} className={styles.linkButton}>
            {detail.runId}
          </Link>
        ) : (
          <button type="button" className={styles.linkButton} onClick={() => onOpenImportRun(detail.runId!)}>
            {detail.runId}
          </button>
        )
      ) : (
        '—'
      ),
      mono: true,
      fullWidth: true,
    },
  ];

  const timeItems: JobDetailMetaItem[] = [
    { label: 'Tạo', value: formatJobDate(detail.createdAt) },
    { label: 'Cập nhật', value: formatJobDate(detail.updatedAt) },
    { label: 'Scheduled', value: formatJobDate(detail.scheduledAt) ?? '—' },
    { label: 'Xử lý', value: formatJobDate(detail.processedAt) ?? '—' },
    { label: 'Retry tiếp', value: formatJobDate(detail.nextRetryAt) ?? '—' },
  ];

  return (
    <>
      <JobDetailMonoId>{detail.eventId}</JobDetailMonoId>

      <JobDetailSection title="Tổng quan">
        <JobDetailMetaGrid items={overviewItems} />
      </JobDetailSection>

      {(detail.progressPercent != null || detail.documentsTotal != null) && (
        <JobDetailSection title="Tiến độ">
          <div style={{ fontSize: 12, color: '#64748b', marginBottom: 6 }}>{progressCaption(detail)}</div>
          <JobProgressBar
            percent={detail.progressPercent}
            done={detail.documentsDone}
            total={detail.documentsTotal}
            unit={detail.progressUnit}
          />
        </JobDetailSection>
      )}

      {(detail.setsSkipped != null && detail.setsSkipped > 0) ||
      (detail.setsFailed != null && detail.setsFailed > 0) ? (
        <JobEventSkipInfo setsSkipped={detail.setsSkipped} setsFailed={detail.setsFailed} />
      ) : null}

      {showFailBlock ? (
        <JobDetailErrorBlock
          error={detail.lastError!}
          category={detail.failureCategory}
          title="Lý do fail"
        />
      ) : null}

      {canRequeue ? (
        <div style={{ marginTop: 12 }}>
          <Button
            type="button"
            variant="secondary"
            disabled={requeuing}
            onClick={handleRequeue}
            data-testid="event-requeue-btn"
          >
            {requeuing ? 'Đang requeue…' : 'Requeue — đưa vào hàng đợi'}
          </Button>
        </div>
      ) : null}

      <JobDetailSection title="Nguồn / tenant">
        <JobDetailMetaGrid items={sourceItems} />
      </JobDetailSection>

      <JobDetailSection title="Tracking">
        <JobDetailMetaGrid items={trackingItems} />
      </JobDetailSection>

      <JobDetailSection title="Thời gian">
        <JobDetailMetaGrid items={timeItems} />
      </JobDetailSection>

      <details style={{ marginTop: 4 }}>
        <summary style={{ cursor: 'pointer', fontWeight: 600, fontSize: 13 }}>Payload JSON</summary>
        <pre
          style={{
            marginTop: 8,
            padding: 12,
            background: '#f8fafc',
            borderRadius: 8,
            fontSize: 11,
            overflow: 'auto',
            maxHeight: 280,
          }}
        >
          {detail.payloadJson}
        </pre>
      </details>
    </>
  );
};
