import React, { Suspense } from 'react';
import { MemoryRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import {
  AlertProvider,
  AppLayout,
  ReduxToastContainer,
  ToastProvider,
} from '@linm-soft-org/linm-web-common-components';
import { SimpleNotFoundPage } from './components/layout/SimpleNotFoundPage';
import { ProtectedRoute } from './components/auth/ProtectedRoute';
import { MemoryRouterSync } from './router/MemoryRouterSync';
import { showDevNav, isStandalone } from './dev/isStandalone';
import AdminHomePage from './pages/AdminHomePage';
import AccountsManagementPage from './pages/AccountsManagementPage';
import PermissionsManagementPage from './pages/PermissionsManagementPage';
import CompaniesManagementPage from './pages/CompaniesManagementPage';
import DataCleanupPage from './pages/DataCleanupPage/DataCleanupPage';
import JobsMonitoringHubPage from './pages/JobsMonitoring/JobsMonitoringHubPage';
import JobDashboardPage from './pages/JobsMonitoring/JobDashboardPage';
import JobScheduleConfigPage from './pages/JobsMonitoring/JobScheduleConfigPage';
import JobInternalPage from './pages/JobsMonitoring/JobInternalPage';
import DataSyncSetConfigPage from './pages/JobsMonitoring/DataSyncSetConfigPage';
import ExternalSyncRunsPage from './pages/JobsMonitoring/ExternalSyncRunsPage';
import ExternalSyncVoucherRenumberPage from './pages/JobsMonitoring/ExternalSyncVoucherRenumberPage';
import JobEventsPage from './pages/JobsMonitoring/JobEventsPage';
import JobServerConfigPage from './pages/JobsMonitoring/JobServerConfigPage';

const DevPage = React.lazy(() => import('./dev/DevPage'));

const initialPath =
  typeof window !== 'undefined'
    ? window.location.pathname + window.location.search || '/'
    : '/';

const Root: React.FC = () => (
  <Provider store={store}>
    <AlertProvider>
      <ToastProvider>
        <ReduxToastContainer />
        <MemoryRouter initialEntries={[initialPath]} initialIndex={0}>
          <MemoryRouterSync />
          <Routes>
            {showDevNav && (
              <Route path="/dev" element={<Suspense fallback={null}><DevPage /></Suspense>} />
            )}
            <Route
              path="/admin/*"
              element={
                <ProtectedRoute>
                  <AppLayout />
                </ProtectedRoute>
              }
            >
              <Route index element={<AdminHomePage />} />
              <Route path="accounts" element={<AccountsManagementPage />} />
              <Route path="companies" element={<CompaniesManagementPage />} />
              <Route path="packages" element={<Navigate to="/admin/permissions?tab=packages" replace />} />
              <Route path="permissions" element={<PermissionsManagementPage />} />
              <Route path="data-cleanup" element={<DataCleanupPage />} />
              <Route path="jobs" element={<JobsMonitoringHubPage />} />
              <Route path="jobs/server-config" element={<JobServerConfigPage />} />
              <Route path="jobs/schedule" element={<JobScheduleConfigPage />} />
              <Route path="jobs/dashboard" element={<JobDashboardPage />} />
              <Route path="jobs/inbound" element={<JobDashboardPage />} />
              <Route path="jobs/external-sync" element={<DataSyncSetConfigPage />} />
              <Route path="jobs/external-runs" element={<ExternalSyncRunsPage />} />
              <Route path="jobs/voucher-renumber" element={<ExternalSyncVoucherRenumberPage />} />
              <Route path="jobs/outbound" element={<JobDashboardPage />} />
              <Route path="jobs/internal" element={<JobInternalPage />} />
              <Route path="jobs/events" element={<JobEventsPage />} />
              <Route path="*" element={<SimpleNotFoundPage />} />
            </Route>
            {isStandalone && (
              <Route path="/" element={<Navigate to="/dev" replace />} />
            )}
          </Routes>
        </MemoryRouter>
      </ToastProvider>
    </AlertProvider>
  </Provider>
);

export default Root;
